label("$f$",(-5.2,1),NE*lsf);

// clip((xmin,ymin)--(xmin,ymax)--(xmax,ymax)--(xmax,ymin)--cycle);
draw((-2,-2.2)--(-2,4.2),dashed);
draw((3,-2.2)--(3,4.2),dashed);
draw((-5,1/2)--(5.5,1/2),dashed);
[/asy]

